  "original_ir": "define i1 @test_chained_gep(ptr %p, i64 %a, i64 %b) {
  %gep1 = getelementptr nusw i8, ptr %p, i64 %a
  %gep2 = getelementptr inbounds i8, %gep1, i64 %b
  %cmp = icmp ugt ptr %gep2, %p
  ret i1 %cmp
}",
  "optimized_ir": "define i1 @test_chained_gep(ptr %p, i64 %a, i64 %b) {
